import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface Station {
  name: string;
  distance: string;
  availability: string;
  costPerKWh: number;
}

interface EstimatedChargeCost {
  kWhNeeded: number;
  totalCost: number;
}

interface EVChargingData {
  nearestStations: Station[];
  estimatedChargeCost: EstimatedChargeCost;
}

export default function Widget() {
  const evChargingData = response.data as EVChargingData;
  const { nearestStations, estimatedChargeCost } = evChargingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#009688' }}>
              Nearest Charging Stations
            </Typography>
            <Divider sx={{ mb: 1 }} />
            <Stack spacing={1.5}>
              {nearestStations.slice(0, 3).map((station, index) => (
                <Box key={index}>
                  <Typography variant="body1" fontWeight={500} sx={{ color: '#37474F' }}>
                    {station.name}
                  </Typography>
                  <Stack direction="row" justifyContent="space-between">
                    <Typography variant="caption" color="text.secondary">
                      {station.distance}
                    </Typography>
                    <Chip label={`Availability: ${station.availability}`} size="small" sx={{ color: '#FFF', bgcolor: '#009688', fontSize: '10px' }} />
                    <Typography variant="caption" color="text.secondary">
                      ${station.costPerKWh.toFixed(2)} per kWh
                    </Typography>
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ display: 'flex', alignItems: 'center', mb: 0.5 }}>
              <Info sx={{ fontSize: 16, mr: 0.5 }} />
              Estimated Charge Cost
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              ${estimatedChargeCost.totalCost.toFixed(2)}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {estimatedChargeCost.kWhNeeded} kWh needed
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
